function solve(nums) {
    const onesIndices = [];
    const twosIndices = [];

    // 1. Collect indices of 1s and 2s
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === 1) {
            onesIndices.push(i);
        } else if (nums[i] === 2) {
            twosIndices.push(i);
        }
    }

    // 2. Check if any valid pair exists
    if (onesIndices.length === 0 || twosIndices.length === 0) {
        return -1;
    }

    // 3. Sort the indices (they are naturally sorted from the loop, but sorting ensures robustness if the collection method changes)
    // Since we populated them in increasing order of index, they are already sorted.
    // onesIndices.sort((a, b) => a - b);
    // twosIndices.sort((a, b) => a - b);

    // 4. Find the minimum absolute difference
    let minDiff = Infinity;

    // We need to check every pair (i from onesIndices, j from twosIndices)
    for (const i of onesIndices) {
        for (const j of twosIndices) {
            const diff = Math.abs(i - j);
            if (diff < minDiff) {
                minDiff = diff;
            }
        }
    }

    return minDiff;
}
